class Solution:
    def repairCars(self, ranks: List[int], cars: int) -> int:
        def possible(time):
            return sum((time // (r * n**2)) for r, n in [(r, int((time / (r * n**2)) ** 0.5)) for r in ranks])

        low, high = 0, 10**14
        while low < high:
            mid = (low + high) // 2
            if possible(mid) >= cars:
                high = mid
            else:
                low = mid + 1
        return low
